            }
        } else {
            if (!term_str.empty()) {
                double num = stod(term_str);
                result.const_coeff += num * sign;
            }
        }
    }

    return result;
}

int main() {
    string equation;
    cin >> equation;

    size_t equal_pos = equation.find('=');
    string left_expr = equation.substr(0, equal_pos);
    string right_expr = equation.substr(equal_pos + 1);

